    29→	async isAPIHealthy(
    30→		key: string,
    31→	): Promise<
    32→		| HealthIndicatorResult<
    33→				string,
    34→				'up',
    35→				{ message: string; timestamp: number; uptime: number }
    36→		  >
    37→		| HealthIndicatorResult<string, 'down', { message: string; error: string }>
    38→	> {
    39→		try {
    40→			this.logger.log(`Checking health of ${key}`);
    41→			await fetch(key);
    42→
    43→			return this.healthIndicatorService.check(key).up({
    44→				message: 'API is working',
    45→				timestamp: Date.now(),
    46→				uptime: process.uptime(),
    47→			});
    48→		} catch (error) {
    49→			this.logger.error(`Health check failed for ${key}`, JSON.stringify(error));
    50→			rollbar.error(error as Error);
    51→			return this.healthIndicatorService.check(key).down({
    52→				message: 'API is not responding',
    53→				error: (error as Error).message,
    54→			});
    55→		}
    56→	}
