   150→export function validate(config: Record<string, unknown>): EnvironmentVariables {
   151→	const logger = Logger;
   152→	const validatedConfig = plainToInstance(EnvironmentVariables, config, {
   153→		enableImplicitConversion: true,
   154→	});
   155→
   156→	const errors = validateSync(validatedConfig, {
   157→		skipMissingProperties: false,
   158→		forbidUnknownValues: true,
   159→		stopAtFirstError: true,
   160→		forbidNonWhitelisted: true,
   161→	});
   162→
   163→	if (errors.length > 0) {
   164→		logger.error('Config validation error', errors);
   165→		throw new Error(errors.toString());
   166→	}
   167→
   168→	return validatedConfig;
   169→}
