    53→export const loadEnvVariables = (): ConfigFactory[] => {
    54→	if (isStagingEnv() || isProdEnv()) {
    55→		validate(getEnvVariables());
    56→		return [getEnvVariables];
    57→	}
    58→
    59→	const envFilePath = path.resolve(process.cwd(), getEnvFile());
    60→
    61→	if (!fs.existsSync(envFilePath)) {
    62→		return [() => ({})];
    63→	}
    64→
    65→	const envConfig = dotenv.parse(fs.readFileSync(envFilePath));
    66→
