    21→	private readonly logger = new Logger(HealthController.name);
    22→
    23→	constructor(
    24→		private health: HealthCheckService,
    25→		private disk: DiskHealthIndicator,
    26→		private memory: MemoryHealthIndicator,
    27→		private healthService: HealthService,
    28→	) {}
    29→
    30→	@ApiOperation({ summary: 'Health Check status.' })
    31→	@HealthCheck({ swaggerDocumentation: false })
    32→	@ApiOkResponse({
    33→		description: 'Health check status',
    34→		schema: {
    35→			type: 'object',
    36→			properties: { status: { type: 'string', enum: ['up'] } },
    37→		},
    38→	})
    39→	@ApiResponse({ status: 503, description: 'Service is down' })
    40→	@Get('is_it_up')
    41→	isItUp(): { status: 'up' } {
    42→		return { status: 'up' };
    43→	}
    44→
    45→	@ApiOperation({ summary: 'Working Check status.' })
    46→	@ApiResponse({
    47→		status: HttpStatus.OK,
    48→		description: 'Return status 200 if the application is ready to serve traffic',
    49→	})
    50→	@HealthCheck()
    51→	@Get('is_it_working')
    52→	async isItWorking(): Promise<HealthCheckResult> {
    53→		if (isSIGTERM) {
    54→			return {
    55→				status: 'shutting_down',
    56→				info: {},
    57→				error: {},
    58→				details: {},
    59→			};
    60→		}
    61→
    62→		this.logger.log('Checking application readiness');
    63→
    64→		return await this.health.check([
    65→			() => this.healthService.isAPIHealthy({ key: 'https://docs.nestjs.com' }),
    66→			() => this.healthService.isRedisHealthy(),
    67→			() => this.healthService.isDatabaseHealthy(),
    68→			() => this.healthService.isOpensearchHealthy(),
    69→			() => this.healthService.isOpensearchDashboardsHealthy(),
    70→			() => this.memory.checkHeap('memory_heap', 500 * 1024 * 1024),
    71→			() => this.disk.checkStorage('storage', { path: '/', thresholdPercent: 0.77 }),
    72→		]);
    73→	}
    74→}
