   149→
   150→export function validate({
   151→	config,
   152→}: {
   153→	config: Record<string, unknown>;
   154→}): EnvironmentVariables {
   155→	const logger = Logger;
   156→	const validatedConfig = plainToInstance(EnvironmentVariables, config, {
   157→		enableImplicitConversion: true,
   158→	});
   159→
   160→	const errors = validateSync(validatedConfig, {
   161→		skipMissingProperties: false,
   162→		forbidUnknownValues: true,
   163→		stopAtFirstError: true,
   164→		forbidNonWhitelisted: true,
   165→	});
   166→
   167→	if (errors.length > 0) {
   168→		logger.error('Config validation error', errors);
   169→		throw new Error(errors.toString());
   170→	}
   171→
   172→	return validatedConfig;
   173→}
